mapper.select:
/* selectMordmaList */
select COOCATE 
	 , COOTYPE as COMBOVL
	 , OCOCTNM
	 , COOTYNM as COMBONM
  from MORDMA

  	and COMPKEY = #{userData.compkey}

		and WAREKEY = #{warekey}


		and COOCATE = #{coocate}


		and COOTYPE = #{cootype}


		and COOTYPE IN

			#{item}




			and COUSEYN = #{couseyn}


			and COUSEYN = 'Y'



group by COOTYPE, COOTYNM
order by COOTYPE, COOTYNM
